// 1. GET 402
const quote = await fetch(url).then(r => r.json());
const accept = quote.accepts[0];

// 2. Sign EIP-3009 auth
const nonce = ('0x' + Array.from(crypto.getRandomValues(new Uint8Array(32))).map(b => b.toString(16).padStart(2,'0')).join('')) as Hex;
const now = Math.floor(Date.now()/1000);
const signature = await wallet.signTypedData({
  domain: { name: 'USD Coin', version: '2', chainId: 1, verifyingContract: USDC },
  types: { ReceiveWithAuthorization: [/* fields */] },
  primaryType: 'ReceiveWithAuthorization',
  message: { from: agent, to: accept.payTo, value: BigInt(accept.maxAmountRequired),
             validAfter: BigInt(now - 60), validBefore: BigInt(now + accept.maxTimeoutSeconds), nonce }
});

// 3. POST with X-PAYMENT
const payload = { x402Version: 1, scheme: 'exact', network: 'ethereum',
                  payload: { signature: parseSignature(signature), authorization: {...} } };
await fetch(url, { method: 'POST', headers: { 'X-PAYMENT': btoa(JSON.stringify(payload)) } });
